command.text:
&GetUnitCode; &CommandWhenBalanceBeforeDelete;
if exists(select 1 from cttt20 where loai_tt = 1 and stt_rec = @stt_rec) begin select @$deleteConflict as message return end
delete cttt50 where stt_rec = @stt_rec

script.text:
      /* <flatten type="Javascript"> */
function activeForm(f) {
  f._controlFocus = f.getItem('ngay_ct');
  f.add_onResponseComplete(on$Form$ResponseComplete);
  setFormDefaultValue(f);
  f.$a = {
    t_tien: '[t_tien]:=[t_tien_nt]*[ty_gia]',
    t_tien_pb: '[t_tien_pb]:=[t_tien_pb_nt]*[ty_gia]',
    t_tien_cl_nt: 't_tien_cl_nt:=[t_tien_nt] - [t_tien_pb_nt]',
    t_tien_cl: 't_tien_cl:=[t_tien] - [t_tien_pb]'
  };
}
function closeForm(f) {try {f.remove_onResponseComplete(on$Form$ResponseComplete);} catch (ex) {}}
function setFormDefaultValue(f) {
  if (f._action == 'New') {
    f.getItem('ma_dvcs').value = f._unitCode;
    f.getItem('ten_dvcs%l').value = f._unitName;
  }
  if ($func.trim(f.getItemValue('ma_nt')) == '') {
    f.setItemValue('ma_nt', f._baseCurrency);
    f.getItem('ten_nt%l').value = f._baseCurrencyName;
  }
  var c = f.getItemValue('ma_nt').toUpperCase();
  var v = (c == '' || c == f._baseCurrency);
  f.getItem('t_tien_nt').disabled = v;
  onChangeCurrency$ForInvoice(f, v);
}
function onChangeCurrency$ForInvoice(f, v) {
  f.getItem('t_tien_pb_nt').disabled = f.getItem('ty_gia').disabled = v;
  if (v) {f.setItemValues('t_tien_nt, t_tien_pb_nt, t_tien_cl_nt, ty_gia', [0, 0, 0, 1]);}
}
function onChange$Form$ItemCustomer(o) {o.parentForm.request('Customer', 'Customer', ['ma_kh'], o);}
function onChange$Form$Item(o) {
  var f = o.parentForm, name = o.field.Name;
  switch (name) {
    case 'ma_nt':
      var c = f.getItemValue('ma_nt').toUpperCase();
      var v = (c == '' || c == f._baseCurrency);
      onChangeCurrency$ForInvoice(f, v);
      f.executeExpression([f.$a.t_tien_cl]);
      window.setTimeout(String.format('setFocusWhenCurrencyChange(\'{0}\', {1});', f._id, v), 2);
      break;
    case 't_tien_nt':
      f.executeExpression([f.$a.t_tien]);
      f.executeExpression([f.$a.t_tien_cl_nt]);
      f.executeExpression([f.$a.t_tien_cl]);
      break;
    case 't_tien_pb_nt':
      f.executeExpression([f.$a.t_tien_pb]);
      f.executeExpression([f.$a.t_tien_cl_nt]);
      f.executeExpression([f.$a.t_tien_cl]);
      break;
    case 'ty_gia':
      f.executeExpression([f.$a.t_tien]);
      f.executeExpression([f.$a.t_tien_pb]);
      f.executeExpression([f.$a.t_tien_cl]);
      break;
    case 't_tien':
      f.executeExpression([f.$a.t_tien_cl]);
      break;
    case 't_tien_pb':
      f.executeExpression([f.$a.t_tien_cl]);
      break;
    default:
      break;
  }
}
function on$Form$ResponseComplete(sender, e) {
  var f = e.object, context = e.type.Context, result = e.type.Result;
  switch (context) {
    case 'Scattering':
      setFormDefaultValue(f);
      break;
    case 'Customer':
      f.setItemControlBehavior('tk', result[0].Value, result[1].Value, true);
      break;
    default:
      break;
  }
}
function setFocusWhenCurrencyChange(id, v) {
	var f = $find(id);
  var t1 = f.getItem('t_tien'), t2 = f.getItem('t_tien_nt');
  if (v) {if (t2.live) {t1.disabled = false; t1.focus();}}
  else {if (t1.live) {t2.disabled = false; t2.focus();}}
  t2.disabled = v;
}
/* </flatten> */
